readonly AWK_CMD=/bin/awk
readonly BASENAME_CMD=/usr/bin/basename
readonly CAT_CMD=/bin/cat
readonly CURL_CMD=/sbin/curl
readonly DF_CMD=/bin/df
readonly DIRNAME_CMD=/usr/bin/dirname
