DisplayAsStatusReportLine()
{
local package_name="${1:?${FUNCNAME[0]}'()': undefined}"
local package_name_msg="$CHARS_BLANK"
local package_status=''
local package_status_msg=''
local package_installed_version=''
local package_version_msg="$CHARS_BLANK"
local package_upgrade_version=''
local package_upgrade_version_msg=''
local package_path_msg="$CHARS_BLANK"
local mode=''
if QPKG.IsMissing "$package_name"; then
mode=highlighted
elif QPKG.IsNtInstalled "$package_name"; then
mode=muted
else
mode=normal
fi
case $mode in
normal)
if QPKGs-ISenabled.Exist "$package_name"; then
package_status+=" $(ColourTextBrightGreen enabled)"
else
package_status+=" $(ColourTextBrightRed disabled)"
fi
if QPKGs-ACstatus-ok.Exist "$package_name"; then
if QPKGs-ISactive.Exist "$package_name"; then
package_status+=" $(ColourTextBrightGreen active)"
elif QPKGs-ISslow.Exist "$package_name"; then
package_status+=" $(ColourTextBrightOrange slow)"
elif QPKGs-ISstarting.Exist "$package_name"; then
package_status+=" $(ColourTextBrightOrange starting)"
elif QPKGs-ISstopping.Exist "$package_name"; then
package_status+=" $(ColourTextBrightOrange stopping)"
elif QPKGs-ISrestarting.Exist "$package_name"; then
package_status+=" $(ColourTextBrightOrange restarting)"
elif QPKGs-ISunknown.Exist "$package_name"; then
package_status+=" $(ColourTextBrightOrange unknown)"
else
package_status+=" $(ColourTextBrightRed inactive)"
fi
else
package_status+=" $(ColourTextBrightOrange unknown)"
fi
if [[ -n $package_status ]]; then
package_status="$(Trim "$package_status")"
package_status_msg="${package_status// /, }"
fi
package_status_msg="${CHARS_NORMAL}${package_status_msg}"
package_installed_version="$(QPKG.Local.GetVer "$package_name")"
QPKG.IsUpgradable "$package_name" && package_upgrade_version="$(QPKG.Avail.GetVer "$package_name")"
package_version_msg+="$package_installed_version"
if [[ -n $package_upgrade_version ]]; then
package_version_msg+=" ($(ColourTextBrightOrange "$package_upgrade_version"))"
package_name_msg+="$(ColourTextBrightOrange "$package_name")"
else
package_name_msg+="$package_name"
fi
package_path_msg+="$(QPKG.GetInstallationPath "$package_name")"
;;
muted)
package_name_msg+="$(ColourTextDarkGrey "$package_name")"
if ! QPKG.IsArchOK "$package_name"; then
package_status='not installable: incompatible arch'
elif ! QPKG.IsMinOSVerOk "$package_name"; then
package_status="not installable: incompatible $(GetQnapOS) version"
elif ! QPKG.IsMinRAMOk "$package_name"; then
package_status='not installable: insufficient RAM'
else
package_status='not installed'
fi
package_status_msg="$(ColourTextDarkGrey "${CHARS_NORMAL}${package_status}")"
package_version_msg=''
package_path_msg=''
;;
highlighted)
package_name_msg+="$(ColourTextBrightRed "$package_name")"
package_status=missing
package_status_msg="$(ColourTextBrightRedBlink "${CHARS_ALERT}${package_status}")"
package_installed_version="$(QPKG.Local.GetVer "$package_name")"
package_version_msg+="$(ColourTextBrightRed "$package_installed_version")"
package_path_msg+="$(ColourTextBrightRedBlink "$(QPKG.GetInstallationPath "$package_name")")"
esac
if [[ $maxcols -ge 1 && -n $package_name_msg ]]; then
printf "%-$((PACKAGE_NAME_COL_WIDTH+$(LenANSIDiff "$package_name_msg")))s" "$package_name_msg"
fi
if [[ $maxcols -ge 2 && -n $package_status_msg ]]; then
printf "%-$((PACKAGE_STATUS_COL_WIDTH+$(LenANSIDiff "$package_status_msg")))s" "$package_status_msg"
fi
if [[ $maxcols -ge 3 && -n $package_version_msg ]]; then
printf "%-$((package_ver_final_col_width+$(LenANSIDiff "$package_version_msg")))s" "$package_version_msg"
fi
if [[ $maxcols -ge 4 && -n $package_path_msg ]]; then
printf "%-$((PACKAGE_PATH_COL_WIDTH+$(LenANSIDiff "$package_path_msg")))s" "$package_path_msg"
fi
printf '\n'; linespace_visible=false
}
