printf '\n'; linespace_visible=false
}
DisplayAsDepsReportLine()
{
local package_name="${1:?${FUNCNAME[0]}'()': undefined}"
local package_name_msg="$CHARS_BLANK"
local package_deps_raw=$(QPKG.GetDependencies "$package_name")
[[ -z $package_deps_raw ]] && package_deps_raw=none
local package_deps=''
local package_deps_msg="$CHARS_NORMAL"
local dep=''
local package_min_ram="$(QPKG.GetMinRAM "$package_name")"
local package_min_ram_msg="$CHARS_BLANK"
if [[ $package_min_ram != none ]]; then
package_min_ram="$(FormatAsThous "$package_min_ram")kB"
fi
local package_min_os="$(QPKG.GetMinOSVer "$package_name")"
package_min_os="${package_min_os:0:1}.${package_min_os:1:1}.${package_min_os:2:1}"
local package_min_os_msg="$CHARS_BLANK"
local package_arch_msg="$CHARS_BLANK"
local mode=''
if QPKG.IsMissing "$package_name"; then
mode=highlighted
elif QPKG.IsNtInstalled "$package_name"; then
mode=muted
else
mode=normal
fi
case $mode in
normal)
package_name_msg+="$package_name"
if [[ $package_deps_raw != none ]]; then
for dep in $package_deps_raw; do
[[ -n $package_deps ]] && package_deps+=' '
if QPKG.IsInstalled "$dep" && QPKG.IsEnabled "$dep"; then
package_deps+="$(ColourTextBrightGreen "$dep")"
else
package_deps+="$(ColourTextBrightRed "!$dep")"
fi
done
else
package_deps+="$(ColourTextBrightGreen "$package_deps_raw")"
fi
package_deps_msg+="${package_deps// /, }"
if QPKG.IsMinRAMOk "$package_name"; then
package_min_ram_msg+="$(ColourTextBrightGreen "$package_min_ram")"
else
package_min_ram_msg+="$(ColourTextBrightRed "!$package_min_ram")"
fi
if QPKG.IsMinOSVerOk "$package_name"; then
package_min_os_msg+="$(ColourTextBrightGreen "$package_min_os")"
else
package_min_os_msg+="$(ColourTextBrightRed "!$package_min_os")"
fi
if QPKG.IsArchOK "$package_name"; then
package_arch_msg+="$(ColourTextBrightGreen true)"
else
package_arch_msg+="$(ColourTextBrightRed '!false')"
fi
;;
muted)
package_name_msg+="$(ColourTextDarkGrey "$package_name")"
package_deps_msg="$(ColourTextDarkGrey "${CHARS_NORMAL}${package_deps_raw}")"
if QPKG.IsMinRAMOk "$package_name"; then
package_min_ram_msg+="$(ColourTextDarkGrey "$package_min_ram")"
else
package_min_ram_msg+="$(ColourTextBrightOrange "*$package_min_ram")"
fi
if QPKG.IsMinOSVerOk "$package_name"; then
package_min_os_msg+="$(ColourTextDarkGrey "$package_min_os")"
else
package_min_os_msg+="$(ColourTextBrightOrange "*$package_min_os")"
fi
if QPKG.IsArchOK "$package_name"; then
package_arch_msg+="$(ColourTextDarkGrey true)"
else
package_arch_msg+="$(ColourTextBrightOrange '*false')"
fi
;;
highlighted)
package_name_msg+="$(ColourTextBrightRed "$package_name")"
package_deps_msg="$(ColourTextDarkGrey "${CHARS_NORMAL}${package_deps}")"
if QPKG.IsMinRAMOk "$package_name"; then
package_min_ram_msg+="$(ColourTextBrightGreen "$package_min_ram")"
else
package_min_ram_msg+="$(ColourTextBrightRed "!$package_min_ram")"
fi
if QPKG.IsMinOSVerOk "$package_name"; then
package_min_os_msg+="$(ColourTextBrightGreen "$package_min_os")"
else
package_min_os_msg+="$(ColourTextBrightRed "!$package_min_os")"
fi
if QPKG.IsArchOK "$package_name"; then
package_arch_msg+="$(ColourTextBrightGreen true)"
else
package_arch_msg+="$(ColourTextBrightRed '!false')"
fi
esac
if [[ $maxcols -ge 1 && -n $package_name_msg ]]; then
printf "%-$((PACKAGE_NAME_COL_WIDTH+$(LenANSIDiff "$package_name_msg")))s" "$package_name_msg"
fi
if [[ $maxcols -ge 2 && -n $package_deps_msg ]]; then
printf "%-$((PACKAGE_DEPENDENCIES_COL_WIDTH+$(LenANSIDiff "$package_deps_msg")))s" "$package_deps_msg"
fi
if [[ $maxcols -ge 3 && -n $package_min_ram_msg ]]; then
printf "%-$((PACKAGE_MIN_RAM_COL_WIDTH+$(LenANSIDiff "$package_min_ram_msg")))s" "$package_min_ram_msg"
fi
if [[ $maxcols -ge 4 && -n $package_min_os_msg ]]; then
printf "%-$((PACKAGE_MIN_OS_COL_WIDTH+$(LenANSIDiff "$package_min_os_msg")))s" "$package_min_os_msg"
fi
if [[ $maxcols -ge 5 && -n $package_arch_msg ]]; then
printf "%-$((PACKAGE_ARCH_COL_WIDTH+$(LenANSIDiff "$package_arch_msg")))s" "$package_arch_msg"
fi
printf '\n'; linespace_visible=false
}
DisplayAsHelpTitleFileNamePlusSomething()
{
WriteEmptyLineIfNoneExists
printf "${CHARS_SPECIAL}%-${FILE_NAME_COL_WIDTH}s ${CHARS_SPECIAL}%s\n" "$(Capitalise "${1:-}"):" "$(Capitalise "${2:-}"):"
linespace_visible=false
}
DisplayAsHelpTitle()
{
WriteEmptyLineIfNoneExists
printf "${CHARS_SPECIAL}%s\n" "$(Capitalise "${1:-}" | tr -s ' ')"
linespace_visible=false
}
DisplayAsHelpTitleHighlighted()
{
WriteEmptyLineIfNoneExists
printf "$(ColourTextBrightOrange "${CHARS_SPECIAL}%s\n")" "$(Capitalise "${1:-}")"
linespace_visible=false
}
DisplayAsIndentPrefixActionResultDurationReason()
{
local duration=''
[[ -n ${4:-} ]] && duration="$(FormatMillisecsToMinutesSecs "$4")"
printf "%${ACTION_RESULT_INDENT}s" ''
if [[ -z ${5:-} ]]; then
printf "%s%s %s%s" "${1:-}" "$(Lowercase "${2:-}")" "${3:-}" "$([[ -n $duration ]] && printf ' in %s' "$duration")"
else
printf "%s%s %s%s\n%${ACTION_RESULT_INDENT}s${CHARS_DROPEND}%s" "${1:-}" "$(Lowercase "${2:-}")" "${3:-}" "$([[ -n $duration ]] && printf ' in %s' "$duration")" '' "$5"
fi
printf '\n'; linespace_visible=false
}
EraseThisLine()
{
[[ ${opts_verbose:-false} = false ]] || return 0
printf '\033[2K\r'
linespace_visible=true
} >&2
Display()
{
echo -e "${1:-}"
linespace_visible=false
}
DisplayWait()
{
printf '%s' "${1:-}"
}
