DisplayFileInWindow()
{
local showlinenumbers=false
local showlinenumbers_msg=''
local jumptoend=false
local jumptoend_msg=''
local onescreen=false
local onescreen_msg=''
local filename="${1:-}"
if [[ ! -e $filename ]]; then
echo "filename '$filename' not found"
return 1
fi
case 'linenumbers' in
${2:-}|${3:-}|${4:-})
showlinenumbers=true
esac
case 'jumptoend' in
${2:-}|${3:-}|${4:-})
jumptoend=true
esac
case 'onescreen' in
${2:-}|${3:-}|${4:-})
onescreen=true
esac
if [[ $opts_verbose = true ]]; then
if [[ -e $CAT_CMD ]]; then
$CAT_CMD "$filename"
return
else
echo "$(<$1)"
return
fi
fi
if [[ -e $GNU_LESS_CMD ]]; then
[[ $showlinenumbers = true ]] && showlinenumbers_msg=' --LINE-NUMBERS'
[[ $jumptoend = true ]] && jumptoend_msg=' +G'
[[ $onescreen = true ]] && onescreen_msg=' --quit-if-one-screen'
LESSSECURE=1 ${GNU_LESS_CMD}${jumptoend_msg}${onescreen_msg} --quit-on-intr --tilde${showlinenumbers_msg} --RAW-CONTROL-CHARS --prompt ' use arrow-keys to scroll up-down & left-right, press Q to quit ' "$filename"
return
fi
if [[ -e $LESS_CMD ]]; then
[[ $showlinenumbers = true ]] && showlinenumbers_msg='N'
$LESS_CMD -${showlinenumbers_msg}~ "$filename"
return
fi
if [[ $showlinenumbers = true ]]; then
if [[ -e $CAT_CMD ]]; then
[[ $showlinenumbers = true ]] && showlinenumbers_msg=' --number'
${CAT_CMD}${showlinenumbers_msg} "$filename"
return
else
$MORE_CMD "$filename"
return
fi
else
if [[ -e $MORE_CMD ]]; then
$MORE_CMD "$filename"
return
elif [[ -e $CAT_CMD ]]; then
$CAT_CMD "$filename"
return
fi
fi
echo "$(<$1)"
}
Log.Last:Paste()
{
local link=''
DisableDebugToArchiveAndFile
ExtractPrevSessFromTail
if [[ -e $SESS_LAST_PATHFILE ]]; then
if Quiz "Press 'Y' to post the most-recent session in your $(ShowTitleName) log to a public pastebin, or any other key to abort"; then
ShowAsProc "uploading $(ShowTitleName) log"
link=$($CAT_CMD --number "$SESS_LAST_PATHFILE" | (exec 3<>/dev/tcp/termbin.com/9999; $CAT_CMD >&3; $CAT_CMD <&3; exec 3<&-))
if [[ $? -eq 0 ]]; then
ShowAsDone "your $(ShowTitleName) log is now online at $(ShowAsURL "$link") and will be deleted in 1 month."
else
ShowAsFail "a link could not be generated. Most likely a problem occurred when talking with $(ShowAsURL 'https://termbin.com')"
fi
else
DebugInfoMinSepr
DebugScript 'user abort'
show_zero_qpkgs=false
return 1
fi
else
ShowAsError 'no last session log found.'
fi
return 0
}
