elif [[ $((index+2)) -lt ${#upgradable_packages[@]} ]]; then
names_formatted+=', '
elif [[ $((index+2)) -eq ${#upgradable_packages[@]} ]]; then
names_formatted+=' & '
fi
done
if [[ ${#upgradable_packages[@]} -eq 1 ]]; then
msg='a new QPKG is'
else
msg='new QPKGs are'
fi
ShowAsInfo "$msg available for $names_formatted."
return 1
}
