else
QPKGs-ISNT${state}.IsAny && DebugQpkg info "ISNT${state}" "($(QPKGs-ISNT${state}:Count)) $(QPKGs-ISNT${state}:ListCSV) "
fi
done
for state in "${QPKG_STATES_TRANSIENT[@]}"; do
