SendActionStatus sk
}
MarkThisActionForkAsSkippedError()
{
[[ -n $proc_fork_pathfile && -e $proc_fork_pathfile ]] && mv "$proc_fork_pathfile" "$proc_skip_error_pathfile"
SendActionStatus se
}
MarkThisActionForkAsFailed()
{
