IPKs-AC"$2"-ok:Add "$1"
return 0
}
NoteIpkAcAsSk()
{
IPKs-AC"$2"-to:Remove "$1"
IPKs-AC"$2"-sk:Add "$1"
return 0
}
NoteIpkAcAsEr()
{
