ModPathToEntware()
{
local -r OPKG=/opt/bin:/opt/sbin
local temp=''
if QPKGs-ISenabled.Exist Entware; then
! [[ $PATH =~ $OPKG ]] || return
temp="$($SED_CMD "s|$OPKG:||" <<< "$PATH:")"
export PATH="$OPKG:${temp%:}"
DebugAsDone 'prepended Entware to $PATH'
else
[[ $PATH =~ $OPKG ]] || return
temp="$($SED_CMD "s|$OPKG:||" <<< "$PATH:")"
export PATH="${temp%:}"
DebugAsDone 'removed Entware from $PATH'
fi
DebugVar PATH
return 0
}
