DebugAsError "$(printf "%${DEBUG_LOG_FIRST_COL_WIDTH}s: %${DEBUG_LOG_SECOND_COL_WIDTH}s\n" "${1:-}" "${2:-}")"
elif [[ ${3:-} = ' ' ]]; then
DebugAsError "$(printf "%${DEBUG_LOG_FIRST_COL_WIDTH}s: %${DEBUG_LOG_SECOND_COL_WIDTH}s: none\n" "${1:-}" "${2:-}")"
elif [[ ${3: -1} = ' ' ]]; then
DebugAsError "$(printf "%${DEBUG_LOG_FIRST_COL_WIDTH}s: %${DEBUG_LOG_SECOND_COL_WIDTH}s: %-s\n" "${1:-}" "${2:-}" "$($SED_CMD 's| *$||' <<< "${3:-}")")"
else
DebugAsError "$(printf "%${DEBUG_LOG_FIRST_COL_WIDTH}s: %${DEBUG_LOG_SECOND_COL_WIDTH}s: %-s\n" "${1:-}" "${2:-}" "${3:-}")"
fi
}
DebugVar()
{
DebugAsVar "\$$1 : '${!1:-undefined}'"
}
DebugInfo()
{
[[ -n ${1:-} ]] || return
if [[ ${2:-} = ' ' || ${2:-} = "'' " ]]; then
DebugAsInfo "$1: none"
elif [[ -n ${2:-} ]]; then
DebugAsInfo "$1: ${2:-}"
else
DebugAsInfo "$1"
fi
}
Func:Init()
{
local -r VAR_NAME=${FUNCNAME[1]}_STARTSECONDS
local var_safe_name=${VAR_NAME//[.-]/_}
var_safe_name=${var_safe_name//:/_}
eval "$var_safe_name=$(/bin/date +%s%N)"
DebugAsFuncEn
}
Func:Exit()
{
local -r VAR_NAME=${FUNCNAME[1]}_STARTSECONDS
local var_safe_name=${VAR_NAME//[.-]/_}
var_safe_name=${var_safe_name//:/_}
DebugAsFuncEx "${1:-0}" "$(ShowAsDuration "$(CalcMilliDifference "${!var_safe_name}" "$(/bin/date +%s%N)")")"
return ${1:-0}
}
FuncFork:Init()
{
original_sess_active_pathfile="$sess_active_pathfile"
sess_active_pathfile="$($MKTEMP_CMD /var/log/"${FUNCNAME[1]}"_XXXXXX)"
local -r VAR_NAME=${FUNCNAME[1]}_STARTSECONDS
local var_safe_name=${VAR_NAME//[.-]/_}
var_safe_name=${var_safe_name//:/_}
eval "$var_safe_name=$(/bin/date +%s%N)"
DebugAsFuncEn
}
FuncFork:Exit()
{
local -r VAR_NAME=${FUNCNAME[1]}_STARTSECONDS
local var_safe_name=${VAR_NAME//[.-]/_}
var_safe_name=${var_safe_name//:/_}
SendActionStatus ex
DebugAsFuncEx "${1:-0}" "$(ShowAsDuration "$(CalcMilliDifference "${!var_safe_name}" "$(/bin/date +%s%N)")")"
if [[ -n $sess_active_pathfile && -e $sess_active_pathfile ]]; then
if [[ -s $sess_active_pathfile ]]; then
$CAT_CMD "$sess_active_pathfile" >> "$original_sess_active_pathfile"
fi
rm -f "$sess_active_pathfile"
fi
sess_active_pathfile="$original_sess_active_pathfile"
original_sess_active_pathfile=''
exit ${1:-0}
}
CalcMilliDifference()
{
echo "$((($2-$1)/1000000))"
}
ShowAsDuration()
{
if [[ ${1:-0} -lt 30000 ]]; then
echo "$(FormatAsThous "${1:-0}")ms"
else
FormatSecsToHoursMinutesSecs "$(($1/1000))"
fi
}
DebugAsFuncEn()
{
DebugThis "(>>) ${FUNCNAME[2]}()"
}
DebugAsFuncEx()
{
DebugThis "(<<) ${FUNCNAME[2]}|${1:-0}|${2:-}"
}
DebugAsProc()
{
[[ -n $1 ]] && DebugThis "(--) $1"
}
DebugAsDone()
{
[[ -n $1 ]] && DebugThis "(==) $1"
}
DebugAsDetect()
{
[[ -n $1 ]] && DebugThis "(**) $1"
}
DebugAsInfo()
{
[[ -n $1 ]] && DebugThis "(II) $1"
}
DebugAsWarn()
{
[[ -n $1 ]] && DebugThis "(WW) $1"
}
DebugAsError()
{
[[ -n $1 ]] && DebugThis "(EE) $1"
}
DebugAsLog()
{
[[ -n $1 ]] && DebugThis "(LL) $1"
}
DebugAsVar()
{
[[ -n $1 ]] && DebugThis "(vv) $1"
}
DebugThis()
{
[[ -n ${1:-} ]] || return
[[ ${opts_verbose:-false} = true ]] && ShowAsDebug "$1"
WriteToLog dbug "$1"
}
AddExtLogToSessLog()
{
local linebuff=''
local original_verbose=false
if [[ $opts_verbose = true ]]; then
original_verbose=true
opts_verbose=false
fi
DebugAsLog 'adding external log to main log'
DebugExtLogMinSepr
DebugAsLog "$(ShowAsLogFilename "${1:?${FUNCNAME[0]}'()': undefined}")"
while read -r linebuff; do
DebugAsLog "$linebuff"
done < "$1"
DebugExtLogMinSepr
opts_verbose=$original_verbose
}
ShowAsProcLong()
{
ShowAsProc "${1:-} (might take a while)" "${2:-}"
}
ShowAsProc()
{
[[ -n ${1:-} ]] || return
local suffix=''
[[ -n ${2:-} ]] && suffix="${2:-}"
WriteToDisplayRewriteInPlaceThenWait "$(ColourTextBrightYellow proc)" "$1 $CHARS_ELLIPSIS $suffix"
WriteToLog proc "${1}${suffix}"
[[ ${opts_verbose:=false} = true ]] && Display
} >&2
ShowAsDebug()
{
[[ -n ${1:-} ]] || return
WriteToDisplay "$(ColourTextBlackOnCyan dbug)" "$1"
}
ShowAsInfo()
{
[[ -n ${1:-} ]] || return
EraseThisLine
WriteToDisplay "$(ColourTextBrightYellow note)" "$1"
WriteToLog note "$1"
} >&2
ShowAsQuiz()
{
[[ -n ${1:-} ]] || return
WriteToDisplayThenWait "$(ColourTextBrightOrangeBlink quiz)" "$1:"
WriteToLog quiz "$1:"
}
ShowAsQuizDone()
{
[[ -n ${1:-} ]] || return
WriteToDisplay "$(ColourTextBrightOrange quiz)" "$1"
}
ShowAsDone()
{
[[ -n ${1:-} ]] || return
EraseThisLine
WriteToDisplay "$(ColourTextBrightGreen 'done')" "$1"
WriteToLog 'done' "$1"
} >&2
ShowAsWarn()
{
[[ -n ${1:-} ]] || return
EraseThisLine
WriteToDisplay "$(ColourTextBrightOrange warn)" "$1"
WriteToLog warn "$1"
} >&2
ShowAsAbort()
{
[[ -n ${1:-} ]] || return
WriteToDisplay "$(ColourTextBrightRed bort)" "$1"
WriteToLog bort "$1"
Self.Error:Set
} >&2
ShowAsFail()
{
[[ -n ${1:-} ]] || return
local capitalised="$(Capitalise "$1")"
EraseThisLine
WriteToDisplay "$(ColourTextBrightRed fail)" "$capitalised"
WriteToLog fail "$capitalised"
} >&2
ShowAsError()
{
[[ -n ${1:-} ]] || return
local capitalised="$(Capitalise "$1")"
EraseThisLine
WriteToDisplay "$(ColourTextBrightRed derp)" "$capitalised"
WriteToLog derp "$capitalised"
Self.Error:Set
} >&2
ShowAsPercentProgress()
{
local tier=''
local -r PACKAGE_TYPE="${2:?${FUNCNAME[0]}'()': undefined}"
declare -i -r OK_COUNT=${3:-0}
declare -i -r SKIP_COUNT=${4:-0}
declare -i -r FAIL_COUNT=${5:-0}
declare -i -r TOTAL_COUNT=${6:-0}
local -r ACTION_PRESENT_MSG="${7:?${FUNCNAME[0]}'()': undefined}"
local -r DURATION=${8:-}
local progress_msg=''
[[ -n $1 && $1 != all ]] && tier=" $(Lowercase "$1")"
progress_msg="$(PercFrac "$OK_COUNT" "$SKIP_COUNT" "$FAIL_COUNT" "$TOTAL_COUNT")"
if [[ $DURATION != long ]]; then
ShowAsProc "$ACTION_PRESENT_MSG ${TOTAL_COUNT}${tier} ${PACKAGE_TYPE}$(Pluralise "$TOTAL_COUNT")" "$progress_msg"
else
ShowAsProcLong "$ACTION_PRESENT_MSG ${TOTAL_COUNT}${tier} ${PACKAGE_TYPE}$(Pluralise "$TOTAL_COUNT")" "$progress_msg"
fi
[[ $((OK_COUNT+SKIP_COUNT+FAIL_COUNT)) -ge $TOTAL_COUNT ]] && sleep 1
return 0
}
PercFrac()
{
declare -i -r OK_COUNT=${1:-0}
declare -i -r SKIP_COUNT=${2:-0}
declare -i -r FAIL_COUNT=${3:-0}
declare -i -r TOTAL_COUNT=${4:-0}
local -i progress_count="$((OK_COUNT+SKIP_COUNT+FAIL_COUNT))"
local perc_msg=''
[[ $TOTAL_COUNT -gt 0 ]] || return
if [[ $progress_count -gt $TOTAL_COUNT ]]; then
progress_count=$TOTAL_COUNT
perc_msg='100%'
else
perc_msg="$((200*(progress_count+1)/(TOTAL_COUNT+1)%2+100*(progress_count+1)/(TOTAL_COUNT+1)))%"
fi
echo "$perc_msg ($(ColourTextBrightWhite "$progress_count")/$(ColourTextBrightWhite "$TOTAL_COUNT"))"
return 0
} 2>/dev/null
ShowAsIterativeProgress()
{
local -r ACTION="${1:?${FUNCNAME[0]}'()': undefined}"
declare -i -r COUNT1=${2:-0}
local -r SUFFIX1="${3:?${FUNCNAME[0]}'()': undefined}"
declare -i -r COUNT2=${4:-0}
local -r SUFFIX2="${5:?${FUNCNAME[0]}'()': undefined}"
local -r DURATION="${6:-short}"
local progress_msg=''
progress_msg="$(ColourTextBrightWhite "$COUNT1") ${SUFFIX1}$(Pluralise "$COUNT1"): $(ColourTextBrightWhite "$COUNT2") ${SUFFIX2}$(Pluralise "$COUNT2")"
if [[ $DURATION != long ]]; then
ShowAsProc "$ACTION" "$progress_msg"
else
ShowAsProcLong "$ACTION" "$progress_msg"
fi
return 0
}
ShowAsActionLogDetail()
{
case ${4:-} in
skipped|skipped-failed)
if [[ -n "${6:-}" ]]; then
DisplayAsIndentPrefixActionResultDurationReason '' "$3" "$2" '' "reason: $6"
else
DisplayAsIndentPrefixActionResultDurationReason '' "$3" "$2" '' "no reason was provided by $(ShowTitleName)"
fi
;;
failed)
if [[ -n "${6:-}" ]]; then
if QPKG.IsCanLog "$2"; then
DisplayAsIndentPrefixActionResultDurationReason 'Unable to ' "$3" "$2" "$5" "For more information, please check the service log: /etc/init.d/$($BASENAME_CMD "$(QPKG.GetServicePathFile "$2")") log"
else
DisplayAsIndentPrefixActionResultDurationReason 'Unable to ' "$3" "$2" "$5" "reason: $6"
fi
else
DisplayAsIndentPrefixActionResultDurationReason 'Unable to ' "$3" "$2" "$5" 'no reason was provided by the service script'
fi
;;
*)
DisplayAsIndentPrefixActionResultDurationReason '' "$3" "$2" "$5"
esac
}
WriteToDisplayThenWait()
{
local -i width=4
[[ $colourful = true ]] && width=10
prev_msg=$(printf "%-${width}s: %s" "${1:-}" "${2:-}")
DisplayWait "$prev_msg"
return 0
}
WriteToDisplayRewriteInPlaceThenWait()
{
local -i width=4
[[ $colourful = true ]] && width=10
prev_msg=$(printf "%-${width}s: %s" "${1:-}" "${2:-}")
DisplayWait "$(printf '\033[2K\r')$prev_msg"
return 0
}
WriteToDisplay()
{
local -i width=4
local -i length=0
local -i blanking_length=0
local msg=''
local strbuffer=''
[[ ${colourful:=true} = true ]] && width=10
msg=$(printf "%-${width}s: %s" "${1:-}" "${2:-}")
if [[ $msg != "${prev_msg:=''}" ]]; then
prev_length=$((${#prev_msg}+1))
length=$((${#msg}+1))
strbuffer=$(echo -en "\r$msg ")
if [[ $length -lt $prev_length ]]; then
blanking_length=$((length-prev_length))
strbuffer+=$(printf "%${blanking_length}s")
fi
Display "$strbuffer"
fi
return 0
}
WriteToLog()
{
[[ -n ${1:-} && -n ${2:-} ]] || return
[[ ${opts_debug:=false} = true && -n $sess_active_pathfile ]] && printf '%-4s: %s\n' "$(StripANSI "$1")" "$(StripANSI "$2")" >> "$sess_active_pathfile"
}
